var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"결론부터 말하면…… 성배란, 살아있는 인간입니다.","JPN":"結論から言いますと……聖杯とは、生きている人間です。","ENG":"In a nutshell... the Holy Grail is a living human.","TWN":"從結論說起……聖杯，就是活生生的人。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"적어도 학회는 그렇게 생각하고 있어요.","JPN":"少なくとも学会ではそう捉えています。","ENG":"At least that is what the Society thinks.","TWN":"至少學會是這麼認為的。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"성배가 인간이라고?","JPN":"聖杯が人間？","ENG":"The Holy Grail is a person?","TWN":"聖杯是人？"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"갑자기 무슨 뚱딴지 같은 소리야, 종이 수녀?","JPN":"ペーパーシスター、何とぼけたこと言ってんだ？","ENG":"What kind of nonsense is that, paper nun?","TWN":"你突然在說什麼傻話，紙修女？"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"지난 성무에서 심의회는 관리거부 구역의 어떤 이교도 마을을 조사했던 적이 있습니다.","JPN":"前回の聖務で、審議会は管理拒否区域のある異教徒の村を調査しました。","ENG":"During the last sacred mission, the Miracle Investigation Council investigated a pagan village in the Anti-Administration Zone.","TWN":"在上次的聖務，議會曾經調查過拒絕管理區域的某個異教徒村落。"},"stage":{"bg":"VATICAN_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그곳에서 집단 광증 및 소요 사태가 발생하고 있다는 제보를 받았기 때문이었죠.","JPN":"そこで集団狂症や騒動が発生しているという報告があったのです。","ENG":"There were reports of mass mania and civil unrest occurring over there.","TWN":"因為接到舉報說，那裡發生集體癲狂騷動事件。"},"stage":{"bg":"VATICAN_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"결과적으로 그곳은 당시 학회장, 안나 맥크레디가 의식을 위해 준비한 공간이었어요.","JPN":"調べたところ、そこは当時の学会長、アンナ・マクレディーが儀式のために設けた場所ということがわかりました。","ENG":"In the end, it was found out that the place was used by the then-President, Anna MacCready, for her ritual.","TWN":"結果，那裡是當時的學會長，安娜·麥克蕾蒂為儀式準備的空間。"},"stage":{"bg":"VATICAN_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그래서 자네가 안나 맥크레디라는 이름에 반응했던 거로군.","JPN":"君がアンナ・マクレディーという名前に反応したのはそのせいか。","ENG":"So that's why you reacted to the name, Anna MacCready.","TWN":"所以你才會對安娜·麥克蕾蒂這個名字有反應。"},"stage":{"bg":"VATICAN_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"네, 부끄럽지만 그 이름을 듣고서야 비로소 깨달을 수 있었습니다.","JPN":"はい、お恥ずかしいですがその名前を聞いてやっと気がつきました。","ENG":"Yes. I am embarrassed to admit that I only realized after hearing that name.","TWN":"是的，我很慚愧，因為聽到這個名字後我才意識到。"},"stage":{"bg":"VATICAN_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"조사 결과, 안나 맥크레디는 오래전부터 자신의 영생을 위해 의식을 옮길 그릇을 선별해 두었어요.","JPN":"調査の結果、アンナ・マクレディーは以前より不老不死を得るために、自分の魂を移す器を選別しておきました。","ENG":"According to the investigation's findings, Anna MacCready has long sought a vessel to transfer her consciousness for eternal life.","TWN":"調查結果顯示，安娜·麥克蕾蒂從很久以前開始就為自己的永生挑選了轉移意識的器皿。"},"stage":{"bg":"VATICAN_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"즉, 그 이교도 마을 말고도 그릇을 선별하는 시설은 더 있었다는 뜻이죠.","JPN":"つまり、器を選び出すための施設はあの異教徒の村だけではなかったということです。","ENG":"In other words, there were more facilities besides that pagan village that were used for choosing the right vessel.","TWN":"也就是說，除了異教徒村落之外，還有篩選器皿的設施。"},"stage":{"bg":"VATICAN_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"실제로 전 그곳에서 구출한 사교도 아이가 <color=#ffd34c>무언가</color>에 깃들어 있는 것을 목격하였습니다.","JPN":"実際、私はそこから救出した邪教徒の子どもに<color=#ffd34c>何か</color>が取り憑いているところを目撃しました。","ENG":"I have also witnessed the pagan child whom we rescued being possessed by <color=#ffd34c>something</color> myself.","TWN":"事實上，我親眼目睹了從那裡救出的異教徒孩童身體裡寄宿著<color=#ffd34c>某種東西</color>的事實。"},"stage":{"bg":"LAB_02","slots":{"L":null,"C":{"char_id":"CHILDREN_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그 아이를 읽어내기 위해 직접 심문을 진행하기도 했지만, 그 결과는…….","JPN":"その子どもの潜在意識を読み取るために尋問を行いましたが……","ENG":"I interrogated her myself to read her, but the results of that were...","TWN":"為了從那個孩子身上獲取情報，我親自進行了審問，但結果……"},"stage":{"bg":"LAB_02","slots":{"L":null,"C":{"char_id":"CHILDREN_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"어, 어떻게 됐는데?","JPN":"ど、どうなったんだ？","ENG":"H-how did it go?","TWN":"怎，怎麼樣了？"},"stage":{"bg":"LAB_02","slots":{"L":null,"C":{"char_id":"CHILDREN_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"많은 일이 있었습니다.","JPN":"お話するには長くなります。","ENG":"A lot had happened.","TWN":"發生了很多事情。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"어, 그렇구나. 미안.","JPN":"あ……そうか。悪い。","ENG":"Oh, I see. Sorry for asking.","TWN":"呃，原來如此，對不起。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L33_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"흠, 아무튼…….","JPN":"ごほん……とにかく。","ENG":"Hmm... anyway...","TWN":"嗯，總之……"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"신은 자신을 본떠 흙으로 몸을 빚고, 숨을 불어넣어 인간을 창조했다는 해석이 있죠.","JPN":"神は自分を模った体を土で作り、そこに息を吹き込み人間を創造したのだと言われます。","ENG":"There is an interpretation that god made mankind in his own image, made them from dust, and breathed life into them.","TWN":"有解析認為，神以自己為參照，用泥土捏造身體，注入呼吸，並創造了人類。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"즉, 여기서 인간의 육체를 하나의 <color=#ffd34c>그릇</color>으로 빗댄다면…….","JPN":"よって、人間の肉体を一つの<color=#ffd34c>器</color>だとすると……","ENG":"Thus, if we compare a human body to a <color=#ffd34c>vessel</color> here...","TWN":"也就是說，如果把人類的肉體比喻成一個<color=#ffd34c>器皿</color>……"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"성배란, 신의 피를 담는 그릇.","JPN":"聖杯は、神の血を宿す器。","ENG":"The Holy Grail is a vessel that can contain the blood of god.","TWN":"聖杯，就是盛裝神血的器皿。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"다시말해, 신적 존재를 육신에 품고서도 버틸 수 있는 <color=#ffd34c>특이체질</color>의 인간입니다.","JPN":"つまり、神的な存在をその身に宿しても耐えられる、<color=#ffd34c>特異体質</color>の人間です。","ENG":"In other words, it is referring to a human with an <color=#ffd34c>idiosyncratic body type</color> that can embrace a divine being.","TWN":"換句話說，就是肉體能夠承受神之存在的<color=#ffd34c>特殊體質</color>的人類。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"특이체질의 인간이라.","JPN":"特異体質の人間か。","ENG":"A human with an idiosyncratic body type.","TWN":"特殊體質的人類。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}}]`);export{e as default};